class Solution:
    def minimumOperations(self, num: str) -> int:
        n = len(num)
        target = ""
        min_ops = n  # worst case: delete all digits to get 0

        # Check for divisibility by 25
        for i in range(n - 1, -1, -1):
            if num[i] == '0':
                target = '0'
                min_ops = min(min_ops, n - i - 1)
            elif num[i] == '5':
                target = '5'
                for j in range(i - 1, -1, -1):
                    if num[j] == '2':
                        min_ops = min(min_ops, n - i - 1 + n - j - 1)
                        break
        return min_ops if min_ops != n else 1  # if all digits are deleted, return 1 (0 is special)
